vendas = [35.0, 42.5, 20.0]

for i, valor in enumerate(vendas):
    print(f"Dia {i + 1}: R$ {valor:.2f}")

precos_gas = [25.0, 26.5, 28.0, 27.5]

for i in range(1, len(precos_gas)):
    diferenca = precos_gas[i] - precos_gas[i - 1]
    if diferenca > 0:
        print(f"Semana {i}: subiu R$ {diferenca:.2f}")

horas = [8, 9, 7, 10]

for i in range(len(horas)):
    print(f"Posição {i}: {horas[i]} horas")

pecas = [42, 50, 38, 60, 47]

for i in range(1, len(pecas)):
    if pecas[i] < pecas[i - 1]:
        queda = pecas[i - 1] - pecas[i]
        print(f"Dia {i + 1}: queda de {queda} peças em relação ao dia anterior")
